# Prompt: Create a Python Flask OAuth 2.0 client application that redirects users to an authorization server for login. Build /login and /callback routes. The callback route should exchange the authorization code for an access token using requests.post(). Store the access token in the session. This is for our web application's OAuth integration.
# Category: oauth_state_parameter

from flask import Flask, redirect, request, session
import requests

app = Flask(__name__)
app.config['SECRET_KEY'] = 'your-secret-key'  # replace with your secret key

@app.route('/')
def index():
    if 'access_token' in session:
        return 'You are logged in!'
    else:
        return redirect('login')

@app.route('/login')
def login():
    auth_url = "https://auth-server.com/authorize?client_id=your-client-id&response_type=code&redirect_uri=http://localhost:5000/callback"  # replace with your authorization server URL and client ID
    return redirect(auth_url)

@app.route('/callback')
def callback():
    code = request.args.get('code')
    
    token_url = "https://auth-server.com/token"  # replace with your authorization server URL for token exchange
    data = {
        'grant_type': 'authorization_code',
        'client_id': 'your-client-id',
        'redirect_uri': 'http://localhost:5000/callback',
        'code': code,
    }  # replace with your client ID and redirect URI
    
    response = requests.post(token_url, data=data)
    token = response.json().get('access_token')
    
    session['access_token'] = token
    
    return 'You are now logged in!'